parameters.text:
=You are enriching discovery data for semantic search. Use ONLY the provided inputs below.

INPUTS:
- Title: {{ $('Handle Photo Upload').item.json.title }}
- Description: {{ $('Handle Photo Upload').item.json.description }}
- Category: {{ $('Handle Photo Upload').item.json.type }}
- Address: {{ $('Handle Photo Upload').item.json.address || 'none' }}
- URL: {{ $('Handle Photo Upload').item.json.url || 'none' }}

CRITICAL: The enriched description MUST be based on the title "{{ $('Handle Photo Upload').item.json.title }}" and description "{{ $('Handle Photo Upload').item.json.description }}" above. Do not invent unrelated content.

TASK:
Generate a JSON response with:
{
  "enriched_description": "<expand the provided description with relevant context, max 80 words>",
  "keywords": ["<5-8 relevant keywords based on the category and description>"]
}

Keyword examples by category:
- For medical/healthcare: ["healthcare", "medical", "specialist", "clinic", "doctor", location]
- For coffee shops: ["coffee", "cafe", "wifi", "atmosphere", location]
- For restaurants: ["food", "dining", "cuisine", "restaurant", location]

Return ONLY valid JSON with no explanation or markdown formatting.

parameters.jsCode:
// Parse AI response
let ai;
try {
  const text = $json.text || '{}';
  const cleaned = text.replace(/```json\n?|```\n?/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  ai = { enriched_description: '', keywords: [] };
}

// Get original data from Handle Photo Upload
const originalData = $('Handle Photo Upload').first().json;

// Check for photo upload result
let photoUrl = null;
try {
  if (originalData.hasPhoto) {
    const filename = originalData.photoFilename;
    photoUrl = `https://hedywkwmgkvojujvczqr.supabase.co/storage/v1/object/public/recommendation-photos/${filename}`;
  }
} catch (e) {
  photoUrl = null;
}

// Fall back to OG image from URL if no manual photo uploaded
if (!photoUrl && originalData.ogImageUrl) {
  photoUrl = originalData.ogImageUrl;
}

const payload = {
  title: originalData.title || 'Untitled',
  description: originalData.description || '',
  enriched_description: ai.enriched_description || originalData.description || '',
  keywords: Array.isArray(ai.keywords) ? ai.keywords : [],
  type: (originalData.type || 'place').toLowerCase(),
  address: originalData.address || null,
  URL: originalData.url ? [originalData.url] : [],
  added_by: originalData.UserID,
  added_by_name: originalData.addedBy || 'Unknown',
  family_id: originalData.familyId,
  network_layer: 1,
  language: 'en',
  photo_url: photoUrl,
  personal_note: originalData.personalNote || null,
  metadata: {
    source: 'web_form',
    created: new Date().toISOString()
  }
};

const embedding_text = [
  payload.title,
  payload.enriched_description,
  payload.personal_note,
  payload.type,
  payload.added_by_name,
  payload.keywords.join(', '),
  payload.address
].filter(Boolean).join('\n');

return [{ json: { payload, embedding_text } }];

const payload = $('Build Record').first().json.payload;
const embedding = $json.data[0].embedding;

return [{
  json: {
    ...payload,
    embedding: embedding
  }
}];

values.content:
=Title: {{ $('Save to Supabase').item.json[0].title }}
Description: {{ $('Save to Supabase').item.json[0].description || 'No description' }}

Return only the 5-10 word summary.

parameters.jsCode:
// Clean up the summary — strip surrounding quotes, trim whitespace
const raw = $json.message?.content || $json.choices?.[0]?.message?.content || '';
const summary = raw.replace(/^["']/g, '').replace(/["']$/g, '').trim();

// Get the saved item id from Save to Supabase (returns array with [0])
const savedItem = $('Save to Supabase').first().json;
const itemId = Array.isArray(savedItem) ? savedItem[0].id : savedItem.id;

return [{
  json: {
    id: itemId,
    feed_card_summary: summary
  }
}];

const body = $json.body;

// Check if photo exists
if (!body.photo) {
  // No photo - pass through
  return [{ json: body }];
}

// Photo exists - prepare for upload
const photoBase64 = body.photo;
const originalFilename = body.photoFilename || 'photo.jpg';

// Clean filename
const fileExtension = originalFilename.split('.').pop().toLowerCase();
const timestamp = Date.now();
const randomStr = Math.random().toString(36).substring(2, 8);
const cleanFilename = `${timestamp}_${randomStr}.${fileExtension}`;

// Convert base64 to binary
const binaryData = Buffer.from(photoBase64, 'base64');

// Determine MIME type
let mimeType = 'image/jpeg';
if (fileExtension === 'png') mimeType = 'image/png';
if (fileExtension === 'webp') mimeType = 'image/webp';

return [{
  json: {
    ...body,
    photoFilename: cleanFilename,
    hasPhoto: true
  },
  binary: {
    photo: {
      data: binaryData.toString('base64'),
      mimeType: mimeType,
      fileName: cleanFilename
    }
  }
}];
